DarkRPUI=DarkRPUI or {}; DarkRPUI.Scoreboard=DarkRPUI.Scoreboard or {}
function DarkRPUI.Scoreboard.BuildPlayerList(parent) parent:Clear(); local holder,search=DarkRPUI.UI.SearchInput(parent,"Search players",nil); holder:Dock(TOP); holder:SetTall(42); local list=DarkRPUI.UI.CreateScroll(parent); list:Dock(FILL); list:DockMargin(0,8,0,0); local cols=DarkRPUI.Scoreboard.VisibleColumns or {"job","rank","money","level","kills","deaths","ping","voice"}; local function rebuild() list:Clear(); local q=string.lower(search:GetValue() or ""); for _,ply in ipairs(player.GetAll()) do local hay=string.lower(ply:Nick().." "..ply:SteamID()); if q=="" or hay:find(q,1,true) then local r=DarkRPUI.Scoreboard.CreatePlayerRow(list,ply,cols); r:Dock(TOP); r:DockMargin(0,0,0,8) end end end; search.OnChange=rebuild; rebuild() end
